// Generate ACLED API request parameters
const now = Date.now();
const startDate = new Date(now - 30 * 24 * 60 * 60 * 1000).toISOString().split('T')[0];
const endDate = new Date(now).toISOString().split('T')[0];

return {
  json: {
    startDate,
    endDate,
    eventTypes: 'Battles|Explosions/Remote violence|Violence against civilians|Riots|Strategic developments',
  }
};

// ─── Process ACLED events for customs/trade route impact ───

const TRADE_CHOKEPOINTS = [
  { name: 'Red Sea / Bab el-Mandeb', lat: 12.60, lon: 43.33, radiusKm: 500 },
  { name: 'Strait of Hormuz',        lat: 26.57, lon: 56.25, radiusKm: 400 },
  { name: 'Suez Canal',              lat: 30.45, lon: 32.35, radiusKm: 300 },
  { name: 'Gulf of Aden',            lat: 12.78, lon: 45.02, radiusKm: 400 },
  { name: 'Eastern Mediterranean',   lat: 34.00, lon: 34.00, radiusKm: 500 },
  { name: 'Black Sea',               lat: 43.50, lon: 34.00, radiusKm: 500 },
  { name: 'Gulf of Guinea',          lat: 3.00,  lon: 3.00,  radiusKm: 500 },
  { name: 'Malacca Strait',          lat: 2.50,  lon: 101.50, radiusKm: 300 },
];

function haversineKm(lat1, lon1, lat2, lon2) {
  const R = 6371;
  const dLat = ((lat2 - lat1) * Math.PI) / 180;
  const dLon = ((lon2 - lon1) * Math.PI) / 180;
  const a = Math.sin(dLat / 2) ** 2 + Math.cos(lat1 * Math.PI / 180) * Math.cos(lat2 * Math.PI / 180) * Math.sin(dLon / 2) ** 2;
  return R * 2 * Math.atan2(Math.sqrt(a), Math.sqrt(1 - a));
}

const rawData = $input.item.json;
const rawEvents = rawData.data || [];

const events = rawEvents
  .filter(e => {
    const lat = parseFloat(e.latitude || '');
    const lon = parseFloat(e.longitude || '');
    return Number.isFinite(lat) && Number.isFinite(lon) && lat >= -90 && lat <= 90;
  })
  .map(e => {
    const lat = parseFloat(e.latitude);
    const lon = parseFloat(e.longitude);
    const fatalities = parseInt(e.fatalities || '0', 10) || 0;

    // Check proximity to trade chokepoints
    let nearChokepoint = null;
    let chokepointDistance = Infinity;
    for (const cp of TRADE_CHOKEPOINTS) {
      const km = haversineKm(lat, lon, cp.lat, cp.lon);
      if (km < cp.radiusKm && km < chokepointDistance) {
        nearChokepoint = cp.name;
        chokepointDistance = km;
      }
    }

    // Severity score for customs impact
    let severityScore = 20;
    if (fatalities >= 50) severityScore = 100;
    else if (fatalities >= 10) severityScore = 75;
    else if (fatalities >= 1) severityScore = 50;
    if (nearChokepoint) severityScore = Math.min(100, severityScore + 25);

    return {
      id: `acled-${e.event_id_cnty}`,
      eventType: e.event_type || '',
      subEventType: e.sub_event_type || '',
      country: e.country || '',
      admin1: e.admin1 || '',
      location: { latitude: lat, longitude: lon },
      occurredAt: new Date(e.event_date || '').getTime(),
      fatalities,
      actors: [e.actor1, e.actor2].filter(Boolean),
      source: e.source || '',
      nearChokepoint,
      chokepointDistanceKm: nearChokepoint ? Math.round(chokepointDistance) : null,
      severityScore,
    };
  })
  .sort((a, b) => b.severityScore - a.severityScore);

const tradeRelevant = events.filter(e => e.nearChokepoint);
const byCountry = {};
for (const e of events) {
  byCountry[e.country] = (byCountry[e.country] || 0) + 1;
}

return {
  json: {
    source: 'acled',
    pipeline: 'conflict-trade-impact',
    events,
    tradeRelevant,
    summary: {
      totalEvents: events.length,
      tradeRelevantEvents: tradeRelevant.length,
      totalFatalities: events.reduce((s, e) => s + e.fatalities, 0),
      topCountries: Object.entries(byCountry).sort((a, b) => b[1] - a[1]).slice(0, 10),
      chokepoints: [...new Set(tradeRelevant.map(e => e.nearChokepoint))],
    },
    processedAt: new Date().toISOString(),
  }
};
